import React, { useCallback, useEffect, useMemo, useState } from 'react';
import classNames from 'classnames';
import { useLocation, useNavigate } from 'react-router-dom';
import { linmLogo128 } from '@linm-soft-org/linm-web-common-components';
import { resolveShellIcon } from '../../config/shellBranding';
import { navigateInAppPath } from '../../router/navigateInAppPath';
import {
  resolveShellEmbed,
  type ShellEmbedResolve,
} from '../../config/resolveShellEmbedUrl';
import {
  resolveLinmHomeLabel,
  resolveLinmHomePath,
} from '../../config/shellUrlConfig';
import styles from './ShellUrlHomePage.module.css';

const STORAGE_KEY = 'linm-home-collapsed';
const PERMISSION_READY = 'linm:permission:ready';
/** Cross-origin iframe cannot report HTTP status — treat no load after this as error. */
const IFRAME_LOAD_TIMEOUT_MS = 20_000;

type EmbedLoadState = 'idle' | 'loading' | 'loaded' | 'error';

function readCollapsed(): boolean {
  try {
    return sessionStorage.getItem(STORAGE_KEY) === '1';
  } catch {
    return false;
  }
}

function writeCollapsed(collapsed: boolean): void {
  try {
    sessionStorage.setItem(STORAGE_KEY, collapsed ? '1' : '0');
  } catch {
    /* ignore */
  }
}

function resolveFromLocation(pathname: string, search: string): ShellEmbedResolve {
  return resolveShellEmbed(pathname, search);
}

/**
 * External content in iframe + FAB Home → in-shell path (giữ domain Linm).
 * Map menu type=shell → DefaultUrl; re-resolve on permission:ready; forward ?query.
 * Rule: external-app-linm-home — Home không full-navigate ra domain ngoài.
 */
const ShellUrlHomePage: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const homePath = useMemo(() => resolveLinmHomePath(), []);
  const homeLabel = useMemo(() => resolveLinmHomeLabel(), []);
  const homeIcon = useMemo(() => {
    const runtimeIcon = resolveShellIcon();
    return runtimeIcon ?? linmLogo128;
  }, []);

  const [collapsed, setCollapsed] = useState(false);
  const [resolveTick, setResolveTick] = useState(0);
  const [embed, setEmbed] = useState<ShellEmbedResolve>(() =>
    resolveFromLocation(location.pathname, location.search),
  );
  const [loadState, setLoadState] = useState<EmbedLoadState>('idle');
  const [frameKey, setFrameKey] = useState(0);
  const [showOkBanner, setShowOkBanner] = useState(false);

  useEffect(() => {
    const timer = window.setTimeout(() => {
      setCollapsed(readCollapsed());
    }, 0);
    return () => window.clearTimeout(timer);
  }, []);

  // Re-resolve when path/search changes or permissions cache becomes ready.
  useEffect(() => {
    const timer = window.setTimeout(() => {
      setEmbed(resolveFromLocation(location.pathname, location.search));
    }, 0);
    return () => window.clearTimeout(timer);
  }, [location.pathname, location.search, resolveTick]);

  useEffect(() => {
    const onReady = () => {
      setResolveTick((n) => n + 1);
    };
    window.addEventListener(PERMISSION_READY, onReady);
    return () => window.removeEventListener(PERMISSION_READY, onReady);
  }, []);

  const contentUrl = embed.status === 'ok' ? embed.url : null;

  // Reset load state + remount iframe when mapped URL changes.
  useEffect(() => {
    if (!contentUrl) {
      setLoadState('idle');
      setShowOkBanner(false);
      return;
    }
    setShowOkBanner(false);
    setLoadState('loading');
    setFrameKey((k) => k + 1);
  }, [contentUrl]);

  // Load timeout — cross-origin cannot confirm HTTP 404; only "never fired onLoad".
  useEffect(() => {
    if (loadState !== 'loading' || !contentUrl) return undefined;
    const timer = window.setTimeout(() => {
      setLoadState((prev) => (prev === 'loading' ? 'error' : prev));
    }, IFRAME_LOAD_TIMEOUT_MS);
    return () => window.clearTimeout(timer);
  }, [loadState, contentUrl, frameKey]);

  const handleHome = useCallback(
    (e: React.MouseEvent<HTMLAnchorElement>) => {
      e.preventDefault();
      navigateInAppPath(homePath, navigate);
    },
    [homePath, navigate],
  );

  const handleMinimize = useCallback((e: React.MouseEvent<HTMLButtonElement>) => {
    e.preventDefault();
    e.stopPropagation();
    setCollapsed((prev) => {
      const next = !prev;
      writeCollapsed(next);
      return next;
    });
    e.currentTarget.blur();
  }, []);

  const handleRetry = useCallback(() => {
    setResolveTick((n) => n + 1);
    if (contentUrl) {
      setLoadState('loading');
      setFrameKey((k) => k + 1);
    }
  }, [contentUrl]);

  const handleFrameLoad = useCallback(() => {
    setLoadState('loaded');
    setShowOkBanner(true);
  }, []);

  const handleFrameError = useCallback(() => {
    setLoadState('error');
    setShowOkBanner(false);
  }, []);

  useEffect(() => {
    if (!showOkBanner || loadState !== 'loaded') return undefined;
    const timer = window.setTimeout(() => setShowOkBanner(false), 2500);
    return () => window.clearTimeout(timer);
  }, [showOkBanner, loadState]);

  const statusBanner =
    embed.status === 'pending' ? (
      <div className={styles.statusBanner} data-testid="shell-url-status-pending" role="status">
        Đang xác nhận map menu shell…
      </div>
    ) : loadState === 'loading' && contentUrl ? (
      <div className={styles.statusBanner} data-testid="shell-url-status-loading" role="status">
        Đang tải nội dung shell…
      </div>
    ) : loadState === 'error' && contentUrl ? (
      <div className={classNames(styles.statusBanner, styles.statusBannerError)} data-testid="shell-url-status-error" role="alert">
        <span>Không xác nhận được nội dung đã tải (timeout / lỗi iframe).</span>
        <button type="button" className={styles.retryBtn} onClick={handleRetry} data-testid="shell-url-retry">
          Thử lại
        </button>
      </div>
    ) : showOkBanner && loadState === 'loaded' && contentUrl ? (
      <div className={classNames(styles.statusBanner, styles.statusBannerOk)} data-testid="shell-url-status-ok" role="status">
        Shell map OK · {embed.status === 'ok' ? embed.menuPath : ''}
      </div>
    ) : null;

  return (
    <div className={styles.shellPage} data-testid="shell-url-home-page">
      {statusBanner}

      {embed.status === 'pending' ? (
        <main className={styles.body}>
          <div className={styles.hintCard} data-testid="shell-url-pending">
            <div className={styles.hintIcon}>
              <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                <circle cx="12" cy="12" r="10" />
                <path d="M12 6v6l4 2" />
              </svg>
            </div>
            <h2 className={styles.hintTitle}>Đang tải menu</h2>
            <p className={styles.hintText}>
              Chờ permissions cache để map đường dẫn{' '}
              <code>{location.pathname}</code>
              {location.search ? <code>{location.search}</code> : null}
              {' '}sang URL iframe.
            </p>
          </div>
        </main>
      ) : contentUrl ? (
        <iframe
          key={frameKey}
          className={styles.contentFrame}
          data-testid="shell-url-content-frame"
          src={contentUrl}
          title="External application"
          sandbox="allow-same-origin allow-scripts allow-forms allow-popups allow-downloads"
          onLoad={handleFrameLoad}
          onError={handleFrameError}
        />
      ) : (
        <main className={styles.body}>
          <div className={styles.hintCard} data-testid="shell-url-not-found">
            <div className={styles.hintIcon}>
              <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                <circle cx="12" cy="12" r="10" />
                <line x1="12" y1="8" x2="12" y2="12" />
                <line x1="12" y1="16" x2="12.01" y2="16" />
              </svg>
            </div>
            <h2 className={styles.hintTitle}>Không tìm thấy nội dung</h2>
            <p className={styles.hintText}>
              Đường dẫn <code>{location.pathname}</code> không khớp với menu
              {' '}<code>menuType=shell</code> nào (Path + DefaultUrl). Vui lòng
              {' '}kiểm tra Admin → Menu, hoặc quay về trang chủ.
            </p>
            <div className={styles.hintActions}>
              <button
                type="button"
                className={styles.retryBtnSecondary}
                onClick={handleRetry}
                data-testid="shell-url-refresh-map"
              >
                Làm mới map
              </button>
              <a
                className={styles.hintHomeBtn}
                href={homePath}
                onClick={handleHome}
              >
                ← Về Dashboard
              </a>
            </div>
          </div>
        </main>
      )}

      <header
        className={classNames(styles.homeBar, collapsed && styles.homeBarCollapsed)}
        data-linm-home-bar
        aria-label="Platform navigation"
      >
        <div className={styles.homeFab}>
          <a
            className={styles.homeLink}
            data-linm-home-href
            data-testid="shell-url-home-btn"
            href={homePath}
            onClick={handleHome}
            aria-label={homeLabel}
            title={homeLabel}
          >
            <img
              className={styles.homeIcon}
              src={homeIcon}
              width={44}
              height={44}
              alt=""
              aria-hidden
            />
          </a>
          <button
            type="button"
            className={styles.minimizeBtn}
            aria-label="Thu gọn nút Home"
            title="Thu gọn"
            data-testid="shell-url-home-minimize"
            onClick={handleMinimize}
          >
            ×
          </button>
        </div>
      </header>
    </div>
  );
};

export default ShellUrlHomePage;
