const trim = (value?: string) => (value ?? '').trim();

/** Default in-app icon — fallback nếu không có runtime branding */
export const SHELL_ICON_PATH = '/icons/logo-128.png';

export type ShellBrandingSnapshot = {
  title?: string;
  subTitle?: string;
  icon?: string;
  iconFolder?: string;
  navMain?: string;
};

declare global {
  interface Window {
    __LINM_SHELL_BRANDING__?: ShellBrandingSnapshot;
  }
}

export function normalizeIconFolder(raw?: string): string {
  let v = trim(raw).replace(/^\/+|\/+$/g, '');
  if (v.toLowerCase().startsWith('icons/')) v = v.slice(6);
  if (!v || v.includes('..') || v.includes('/')) return '';
  return v;
}

export function shellInAppIconUrl(folder?: string, file = 'logo-128.png'): string {
  const f = normalizeIconFolder(folder);
  return f ? `/icons/${f}/${file}` : `/icons/${file}`;
}

function readRootShellBranding(): ShellBrandingSnapshot | undefined {
  if (typeof window === 'undefined') return undefined;
  const value = window.__LINM_SHELL_BRANDING__;
  return value && typeof value === 'object' ? value : undefined;
}

export const shellBranding = {
  iconFolder: normalizeIconFolder(import.meta.env.VITE_ICON_FOLDER as string),
} as const;

/**
 * Resolve runtime icon URL từ window.__LINM_SHELL_BRANDING__.icon
 * với fallback chain: runtime override → runtime folder → build-time folder → default path.
 * Return undefined nếu không có runtime branding (caller dùng bundled fallback).
 */
export function resolveShellIcon(): string | undefined {
  const fromRoot = readRootShellBranding();
  const rootIcon = trim(fromRoot?.icon);
  if (rootIcon) return rootIcon;
  const rootFolder = normalizeIconFolder(fromRoot?.iconFolder);
  if (rootFolder) return shellInAppIconUrl(rootFolder);
  if (shellBranding.iconFolder) return shellInAppIconUrl(shellBranding.iconFolder);
  return undefined;
}
