import { getPermissionsCacheEntry } from '@linm-soft-org/linm-web-common-components';
import { normalizePath } from '../router/navigateInAppPath';
import { resolveExternalContentUrl } from './shellUrlConfig';
import { isStandalone } from '../dev/isStandalone';

export const MENU_TYPE_SHELL = 'shell';

export interface ShellNavMenuItem {
  path: string;
  defaultUrl: string;
  menuType?: string | null;
}

/** Outcome of mapping shell pathname → iframe URL (menu type=shell). */
export type ShellEmbedResolve =
  | { status: 'pending' }
  | { status: 'not-found' }
  | { status: 'ok'; url: string; menuPath: string };

function readShellNavItems(): ShellNavMenuItem[] {
  const raw = getPermissionsCacheEntry()?.payload?.navItems;
  if (!Array.isArray(raw)) return [];

  const items: ShellNavMenuItem[] = [];
  for (const item of raw) {
    const row = item as {
      path?: string | null;
      defaultUrl?: string | null;
      menuType?: string | null;
    };
    if (!row.path || !row.defaultUrl) continue;
    if ((row.menuType ?? 'route') !== MENU_TYPE_SHELL) continue;
    items.push({
      path: normalizePath(row.path),
      defaultUrl: row.defaultUrl.trim(),
      menuType: row.menuType,
    });
  }
  return items.sort((a, b) => b.path.length - a.path.length);
}

function joinExternalUrl(base: string, suffix: string): string {
  if (!suffix) return base;
  try {
    const url = new URL(base);
    const extra = suffix.startsWith('/') ? suffix : `/${suffix}`;
    url.pathname = `${url.pathname.replace(/\/$/, '')}${extra}`;
    return url.toString();
  } catch {
    const trimmed = base.replace(/\/$/, '');
    const extra = suffix.startsWith('/') ? suffix : `/${suffix}`;
    return `${trimmed}${extra}`;
  }
}

/** Forward shell `?query` onto iframe URL without overwriting keys already on DefaultUrl. */
function mergeShellSearch(embedUrl: string, search: string): string {
  const raw = (search || '').trim();
  if (!raw || raw === '?') return embedUrl;

  const query = raw.startsWith('?') ? raw.slice(1) : raw;
  if (!query) return embedUrl;

  try {
    const url = new URL(embedUrl);
    const incoming = new URLSearchParams(query);
    incoming.forEach((value, key) => {
      if (!url.searchParams.has(key)) {
        url.searchParams.set(key, value);
      }
    });
    return url.toString();
  } catch {
    const sep = embedUrl.includes('?') ? '&' : '?';
    return `${embedUrl}${sep}${query}`;
  }
}

/**
 * Resolve iframe URL from menu type=shell (longest path prefix match).
 * Forwards shell search params onto DefaultUrl (non-destructive merge).
 */
export function resolveShellEmbed(
  pathname: string,
  search = '',
): ShellEmbedResolve {
  const cache = getPermissionsCacheEntry();
  if (!cache && !isStandalone) {
    return { status: 'pending' };
  }

  const current = normalizePath(pathname);
  for (const item of readShellNavItems()) {
    if (current === item.path || current.startsWith(`${item.path}/`)) {
      const suffix = current.slice(item.path.length);
      const joined = joinExternalUrl(item.defaultUrl, suffix);
      return {
        status: 'ok',
        url: mergeShellSearch(joined, search),
        menuPath: item.path,
      };
    }
  }

  if (isStandalone) {
    const fallback = resolveExternalContentUrl();
    if (fallback) {
      return {
        status: 'ok',
        url: mergeShellSearch(fallback, search),
        menuPath: current,
      };
    }
  }

  return { status: 'not-found' };
}

/** @deprecated Prefer resolveShellEmbed — returns URL string or null. */
export function resolveShellEmbedUrl(pathname: string, search = ''): string | null {
  const result = resolveShellEmbed(pathname, search);
  return result.status === 'ok' ? result.url : null;
}

/** First segment of shell menu paths — used for Root MFE route registration audit. */
export function listShellRoutePrefixes(): string[] {
  const prefixes = new Set<string>();
  for (const item of readShellNavItems()) {
    const seg = item.path.split('/').filter(Boolean)[0];
    if (seg) prefixes.add(seg);
  }
  return [...prefixes];
}
